import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch6: ScenarioQuestion[] = [
  q("sq-bg6-1",ip,"behavioral","You showed leadership during a challenging group simulation.","Describe your leadership in a simulation exercise.","During a mass casualty simulation, I naturally stepped into the triage coordinator role. I assessed incoming patients, assigned acuity levels, delegated care to team members based on their strengths, and maintained communication throughout. Our team managed all patients within the time limit. The instructor noted my calm demeanor helped the team stay organized.","Emergent leadership under simulated pressure.","beginner"),
  q("sq-bg6-2",ip,"behavioral","You improved a process during your clinical rotation.","How did you contribute to process improvement?","I noticed medication reconciliation forms were frequently incomplete at admission. I proposed a simple checklist prompting nurses to verify home medications, OTC supplements, and herbal products. After implementation, medication reconciliation completeness improved from 75% to 94%. Small changes in process can have significant safety impacts.","Initiative-driven safety improvement.","beginner"),
  q("sq-bg6-3",ip,"behavioral","You managed a difficult patient relationship.","How did you build rapport with a resistant patient?","A patient with a history of negative healthcare experiences refused care from nursing students. Instead of taking it personally, I introduced myself daily, offered small comforts without clinical expectations, and respected their boundaries. By day three, they allowed me to take vital signs. By discharge, they thanked me for my patience.","Persistence and patience in relationship building.","beginner"),
  q("sq-bg6-4",ip,"clinical_judgment","A patient with asthma develops an acute exacerbation with audible wheezing.","How would you manage an acute asthma exacerbation?","I would position the patient upright, administer prescribed bronchodilators via nebulizer, apply oxygen, monitor peak flow measurements, and assess for signs of respiratory failure (silent chest, inability to speak in sentences, altered mental status). I would have emergency intubation equipment available and notify the provider. Serial assessments are critical to determine if treatment is effective.","Systematic asthma exacerbation management.","intermediate"),
  q("sq-bg6-5",ip,"clinical_judgment","A patient with diabetes insipidus has a urine output of 800 mL in the last hour.","What does excessive urine output indicate in DI?","Diabetes insipidus causes inadequate ADH production or response, resulting in massive dilute urine output. 800 mL/hr indicates uncontrolled DI. I would ensure aggressive IV fluid replacement to match output, check serum sodium and osmolality, administer desmopressin if prescribed, and monitor for dehydration and hypernatremia. Strict I&O and frequent electrolyte monitoring are essential.","DI crisis management with fluid and electrolyte monitoring.","advanced"),
  q("sq-bg6-6",ip,"clinical_judgment","A patient develops chest pain immediately after a central line insertion.","What complication do you suspect?","Chest pain immediately after central line insertion could indicate pneumothorax, hemothorax, or cardiac tamponade depending on the approach and location. I would assess breath sounds, check for tracheal deviation, monitor vital signs, obtain a stat chest X-ray, and notify the provider. I would have chest tube insertion supplies available and prepare for possible emergency intervention.","Post-procedure complication assessment.","advanced"),
  q("sq-bg6-7",ip,"clinical_judgment","A patient on chronic steroid therapy develops moon face, buffalo hump, and striae.","What do these findings indicate?","Moon facies, buffalo hump, and purple striae are classic signs of Cushing syndrome from exogenous steroid use. I would monitor blood glucose (steroids cause hyperglycemia), assess for osteoporosis risk, check blood pressure, monitor for infection signs (steroids mask fever), and discuss with the provider about the lowest effective dose. Abrupt steroid discontinuation must be avoided.","Iatrogenic Cushing syndrome recognition.","intermediate"),
  q("sq-bg6-8",ip,"clinical_judgment","A patient receiving total parenteral nutrition has a blood glucose of 350.","How would you manage TPN-related hyperglycemia?","I would administer insulin per sliding scale protocol, notify the provider about the persistent hyperglycemia, and anticipate adjustments to the TPN formulation. Regular insulin may be added directly to the TPN bag. I would check blood glucose every 4-6 hours and monitor for signs of hyperosmolar state. Tight glucose control during TPN reduces infection risk and improves outcomes.","TPN glucose management with formulation adjustment.","intermediate"),
  q("sq-bg6-9",ip,"scenario_responses","A patient tells you they feel like a burden to their family.","How would you support a patient feeling burdensome?","I would listen empathetically and validate their feelings: 'It is understandable to feel that way when you need help. Your family is here because they love you, not out of obligation.' I would screen for depression, explore the underlying concerns, involve social work for support services, and help identify ways the patient can maintain a sense of purpose and contribution during recovery.","Addressing burden perception with validation and support.","intermediate"),
  q("sq-bg6-10",ip,"scenario_responses","A patient asks you to smuggle in fast food against their dietary restrictions.","How would you handle a food smuggling request?","I would understand their craving while maintaining their health: 'I completely understand—hospital food is not the same as your favorite burger. However, your sodium-restricted diet is protecting your heart right now. Let me work with the dietitian to find options that are closer to what you are craving while keeping you safe. After discharge, we can discuss how to enjoy your favorites in moderation.'","Empathetic diet compliance with creative alternatives.","beginner"),
  q("sq-bg6-11",ws,"prioritization","You have a new admission, two medication passes, and a dressing change due within 30 minutes.","How would you organize four tasks in 30 minutes?","I would prioritize: first, assess the new admission briefly for any acute needs and get them settled. Second, administer the medications since they are time-sensitive. Third, complete the dressing change. I would delegate admission paperwork and vital signs to support staff. I would reassess the new admission more thoroughly after completing time-critical tasks.","Multi-task sequencing with delegation support.","intermediate"),
  q("sq-bg6-12",ws,"prioritization","An alert patient and a confused patient both need medications at the same time.","Which patient gets medications first?","I would administer to the confused patient first because medication administration for confused patients takes longer and requires more assessment. The alert patient is more likely to understand and accept a brief delay. I would also consider medication type—time-critical medications take priority regardless of patient cognition.","Cognitively appropriate sequencing consideration.","beginner"),
  q("sq-bg6-13",ws,"delegation","Your CNA calls in sick and no replacement is available.","How would you manage without CNA support?","I would reprioritize my tasks, focusing on essential nursing care. I would communicate with the charge nurse about the staffing gap. I would defer non-urgent tasks, combine care activities to save time, and ask neighboring nurses if they can assist with specific tasks. I would document the staffing situation. I would not compromise essential patient care.","Resource-limited care management.","intermediate"),
  q("sq-bg6-14",ws,"patient_safety","A patient's wrist identification band is missing.","How would you handle a missing patient identification band?","I would immediately replace the wristband using two patient identifiers to verify identity before applying. I would not administer any medications or perform any procedures until the patient is properly identified. I would investigate how the band was removed and reinforce patient identification protocols with the team.","Immediate identification verification and replacement.","beginner"),
  q("sq-bg6-15",ws,"patient_safety","A patient on a continuous pulse oximetry alarm has their SpO2 alarm set at 80% instead of 90%.","How would you address incorrectly set monitor alarms?","I would immediately correct the alarm parameter to the appropriate level (typically 90-92% for most patients). I would assess whether the patient desaturated below 90% while the alarm was incorrectly set. I would investigate who changed the alarm and why. Alarm fatigue leads staff to silence or adjust alarms inappropriately—this is a significant patient safety concern requiring education and monitoring.","Alarm management safety and alarm fatigue awareness.","intermediate"),
  q("sq-bg6-16",ws,"medication_error","A patient is prescribed a medication they told you they are allergic to.","How would you handle an allergy-medication conflict?","I would not administer the medication. I would verify the allergy details with the patient: type of reaction, severity, and when it occurred. I would contact the prescriber to inform them of the allergy and request an alternative. I would ensure the allergy is prominently documented in the chart and on the allergy band. This is a critical safety catch.","Allergy verification before administration.","beginner"),
  q("sq-bg6-17",ws,"handoff_communication","You are giving report and the receiving nurse interrupts you repeatedly.","How would you manage interruptions during your report?","I would politely redirect: 'I want to make sure I cover everything important. Can I finish my summary and then address your questions at the end?' If specific interruptions are clarifying questions that help the nurse understand, I would welcome those. But constant interruptions risk missing critical information. Structured handoff reduces interruption-related gaps.","Structured handoff with managed interruptions.","beginner"),
  q("sq-bg6-18",ws,"difficult_coworkers","A physician yells at you in front of a patient.","How would you handle being yelled at by a physician?","I would remain calm and not engage in a verbal confrontation in front of the patient. I would say, 'I want to resolve this concern. Can we step outside to discuss it?' After the interaction, I would document the behavior and report it to my charge nurse and manager. Verbal abuse in healthcare is never acceptable and should be reported through formal channels.","De-escalation and formal reporting of verbal abuse.","intermediate"),
  q("sq-bg6-19",ws,"interdisciplinary_communication","A wound care nurse's recommendations differ from what the physician ordered.","How would you navigate conflicting wound care orders?","I would not follow conflicting orders. I would contact the physician to discuss the wound care nurse's recommendations: 'The wound care specialist assessed the patient and recommends a different approach. Can you review their assessment and let me know how you would like to proceed?' I would document the discrepancy and the resolution. Expert consultation should be considered in wound management decisions.","Facilitating specialist-physician wound care alignment.","intermediate"),
  q("sq-bg6-20",ct,"first_shift","You are assigned your first patient death as the primary nurse.","How would you manage your first patient death?","I would ensure the patient was comfortable in their final moments. I would support the family with compassion and patience. I would perform post-mortem care with dignity and respect. I would complete the necessary documentation and notification procedures. Afterward, I would debrief with my preceptor and allow myself to process the emotional impact. I would not suppress my feelings.","First patient death processing with professional support.","intermediate"),
  q("sq-bg6-21",ct,"new_nurse_anxiety","You made an error that was caught before reaching the patient.","How would you handle a near-miss emotionally?","I would feel grateful the error was caught and take it as a serious learning opportunity. I would analyze the root cause of my near-miss and develop a prevention strategy. I would report it through the incident reporting system even though no harm occurred—near-miss data is valuable for system improvement. I would not minimize it because it was caught.","Near-miss as learning opportunity with reporting obligation.","beginner"),
  q("sq-bg6-22",ct,"time_management","You realize you need to change your entire workflow approach.","When is it time to restructure your nursing workflow?","If I am consistently leaving late, missing tasks, or feeling overwhelmed despite effort, it is time to restructure. I would shadow efficient experienced nurses to learn their flow, try different organizational tools, reorganize my geographic workflow, and seek feedback from my preceptor. Different patient populations and unit cultures require different workflow approaches.","Recognizing and acting on inefficiency patterns.","beginner"),
  q("sq-bg6-23",ct,"documentation_challenges","You witness a patient fall but multiple nurses respond.","How do multiple nurses document the same event?","Each nurse documents only what they personally witnessed and did. I would write: 'Heard call for help at 1430. Found patient on floor in room 312. Assessed for injuries: no visible injuries noted, patient alert and oriented, vitals stable. Assisted patient back to bed.' I would not document what another nurse assessed or observed—they document their own perspective.","Individual accountability in multi-responder documentation.","beginner"),
  q("sq-bg6-24",ct,"critical_thinking_drills","A patient has a hemoglobin of 6.5 g/dL.","What does a critically low hemoglobin require?","A hemoglobin of 6.5 (normal 12-16 for women, 14-18 for men) is critically low and likely requires blood transfusion. I would assess for symptoms: tachycardia, dyspnea, fatigue, pallor, and chest pain. I would ensure the patient has a type and screen/crossmatch on file, notify the provider, and anticipate a transfusion order. I would prepare for blood administration and continue monitoring.","Critical anemia assessment with transfusion preparation.","intermediate"),
  q("sq-bg6-25",ct,"critical_thinking_drills","A patient's blood culture comes back positive for MRSA.","What does a positive MRSA blood culture mean clinically?","MRSA bacteremia is a serious, potentially life-threatening infection requiring aggressive treatment. I would ensure the patient is on appropriate isolation precautions, verify that vancomycin or daptomycin therapy has been initiated, check the timing and dose of antibiotics, assess for potential sources (wound, central line, UTI), and monitor for sepsis progression. Follow-up blood cultures are needed to confirm clearance.","MRSA bacteremia management priorities.","advanced"),
  q("sq-bg6-26",pd,"professional_boundaries","A patient tells you intimate personal details about their life.","How would you maintain boundaries during intimate patient disclosures?","I would listen therapeutically without sharing my own intimate personal stories. I would acknowledge their trust: 'Thank you for trusting me with that. I want you to know I will keep this confidential.' I would document relevant clinical information and refer to appropriate support services (chaplain, counselor, social work). Therapeutic listening is different from personal friendship.","Therapeutic boundaries during personal patient disclosures.","beginner"),
  q("sq-bg6-27",pd,"ethical_dilemmas","You believe a do-not-resuscitate order may not reflect the patient's current wishes.","How would you address a potentially outdated DNR?","I would discuss my concerns with the physician and advocate for a goals-of-care conversation with the patient to reaffirm or revise their code status. I would not change the order without the patient's involvement. Advance directives should be reviewed periodically and whenever clinical status changes significantly. The patient's current wishes always take priority over previously documented preferences.","Advance directive review advocacy.","intermediate"),
  q("sq-bg6-28",pd,"workplace_bullying","A colleague spreads rumors about your personal life at work.","How would you address personal rumors at work?","I would address the colleague directly and privately: 'I am aware that personal information about me is being shared with coworkers. I need this to stop immediately. My personal life is not appropriate workplace conversation.' If the behavior continued, I would document it and report to HR. Rumor-spreading can constitute workplace harassment.","Direct confrontation of personal rumor spreading.","intermediate"),
  q("sq-bg6-29",pd,"advocacy","A patient needs physical therapy but their insurance only covers a limited number of sessions.","How would you advocate for extended therapy coverage?","I would work with the PT team to document functional progress and remaining deficits. I would support the provider in submitting medical necessity documentation for additional sessions. I would help the patient access community-based exercise programs. I would connect them with social work for alternative funding sources. Every avenue should be explored before accepting insurance limits that compromise recovery.","Multi-strategy therapy access advocacy.","intermediate"),
  q("sq-bg6-30",pd,"patient_communication","A patient is frustrated because no one has explained what is happening with their care.","How would you address communication breakdown frustrations?","I would sit down and provide a comprehensive update: 'I understand your frustration, and you deserve to know what is happening. Let me walk you through where you are in your treatment, what we are waiting for, and what the plan is going forward.' I would ensure the physician visits the patient to discuss the overall plan. I would implement a communication board with daily goals.","Comprehensive communication recovery with ongoing plan.","beginner"),
  q("sq-bg6-31",cn,"job_offer_negotiation","You are negotiating for a specific orientation length.","How would you negotiate for extended orientation?","I would express my commitment to excellence: 'I want to be fully prepared to provide safe, independent patient care. Research shows that longer orientation periods for new graduates reduce medical errors and improve retention. Could we discuss extending the orientation by two weeks?' I would present evidence that supported orientation leads to better outcomes for the unit.","Evidence-based orientation extension request.","beginner"),
  q("sq-bg6-32",cn,"probation_period","Your preceptor gives you contradictory advice from what you learned in school.","How would you reconcile textbook versus practice differences?","I would ask my preceptor to explain their clinical reasoning: 'In school, we learned to do it this way. Can you explain why you do it differently?' Often, experienced nurses have evidence-based reasons for their variations, or policies have evolved. If the difference involves a safety concern, I would check the facility's current policy and evidence-based guidelines to determine the correct approach.","Critical evaluation of practice variations.","beginner"),
  q("sq-bg6-33",cn,"career_advancement","You are interested in military nursing.","How would you explore military nursing opportunities?","I would research the nursing corps of each military branch (Army, Navy, Air Force). I would understand the commissioning process, training requirements, and service obligations. I would contact a healthcare recruiter for detailed information. Military nursing offers unique experiences: trauma care, global health, leadership development, and service to the country. Prior active duty service or ROTC participation strengthens applications.","Military nursing career exploration.","intermediate"),
  q("sq-bg6-34",ip,"clinical_judgment","A patient with a pericardial effusion develops muffled heart sounds, JVD, and hypotension.","What emergency do these three findings indicate?","Muffled heart sounds, jugular venous distention, and hypotension constitute Beck's triad—indicating cardiac tamponade. Fluid in the pericardial sac is compressing the heart, preventing adequate filling. This is a life-threatening emergency requiring emergent pericardiocentesis. I would call for help, prepare for the procedure, ensure large-bore IV access, administer IV fluids to increase preload, and notify the cardiologist STAT.","Beck's triad recognition for cardiac tamponade.","advanced"),
  q("sq-bg6-35",ws,"patient_safety","A patient on a ventilator accidentally self-extubates.","How would you manage accidental self-extubation?","I would call for help immediately, assess the patient's ability to breathe independently, apply supplemental oxygen, prepare for possible reintubation, and monitor vital signs and oxygen saturation closely. If the patient is maintaining their airway and oxygenation, reintubation may not be immediately necessary. I would assess what led to the self-extubation and implement prevention measures.","Self-extubation emergency response.","advanced"),
  q("sq-bg6-36",ct,"critical_thinking_drills","A patient's troponin is trending upward over serial measurements.","What does a rising troponin trend indicate?","A rising troponin pattern (e.g., 0.04 → 0.15 → 0.45) indicates ongoing myocardial injury and is more concerning than a single elevated value. The pattern helps differentiate acute MI from chronic elevation. I would ensure the patient is on continuous cardiac monitoring, has serial ECGs, and the cardiology team is aware of the trend. Rising troponin typically accelerates the need for cardiac intervention.","Troponin trending for clinical decision-making.","intermediate"),
  q("sq-bg6-37",ip,"behavioral","Tell me about a time you demonstrated empathy.","Describe how you practice empathy in nursing.","A patient who was homeless was embarrassed about their hygiene and apologized repeatedly. Rather than rushing through the admission, I provided a warm bath, clean clothes, and extra time for the assessment. I said, 'Everyone deserves to feel comfortable and cared for. That is why I am here.' The patient visibly relaxed and became much more cooperative with their treatment plan.","Dignity-preserving empathy in action.","beginner"),
  q("sq-bg6-38",ws,"delegation","You are training a CNA on a new monitoring device.","How would you ensure competency with new equipment?","I would demonstrate the device, explain the clinical purpose and critical parameters, have the CNA perform a return demonstration, observe their first independent use, and establish when to escalate findings to me. I would provide a written quick-reference guide and check in periodically. Competency verification is essential before delegating tasks involving new equipment.","Equipment competency verification process.","beginner"),
  q("sq-bg6-39",pd,"ethical_dilemmas","A patient with a terminal illness wants to stop all treatment and go home to die.","How would you support a patient choosing to stop treatment?","I would ensure the patient has decision-making capacity and understands the implications. I would facilitate conversations with the physician and palliative care team. I would arrange hospice referral and home support. I would provide comfort measures and emotional support. I would help the family understand and accept the patient's decision. Choosing quality over quantity of life is a valid, autonomous decision.","Supporting autonomous end-of-life decisions.","advanced"),
  q("sq-bg6-40",cn,"career_advancement","You want to develop leadership skills for a management role.","How would you prepare for nurse management?","I would take on charge nurse assignments, lead unit projects, pursue a management or leadership certificate, develop financial literacy and budgeting skills, study human resources principles, and build conflict resolution competencies. I would seek mentorship from current nurse managers. I would also develop emotional intelligence and self-awareness—technical skills alone do not make effective leaders.","Comprehensive management preparation pathway.","intermediate"),
  q("sq-bg6-41",ip,"clinical_judgment","A patient receiving an aminoglycoside antibiotic complains of ringing in their ears.","What does tinnitus suggest during aminoglycoside therapy?","Tinnitus during aminoglycoside therapy (gentamicin, tobramycin) indicates ototoxicity—drug-induced damage to the inner ear. I would hold the medication, check peak and trough levels, assess hearing acuity, and notify the provider immediately. Ototoxicity can be irreversible. I would also check renal function as impaired kidney function increases aminoglycoside toxicity risk.","Aminoglycoside ototoxicity recognition.","intermediate"),
  q("sq-bg6-42",ws,"medication_error","A patient received the right medication but through the wrong route.","How would you manage a wrong-route medication error?","I would assess the patient for adverse effects specific to the incorrect route. For example, an oral medication given IV could cause serious complications. I would contact poison control and the pharmacist for guidance on the specific medication and route. I would notify the provider, document the error, and complete an incident report. Wrong-route errors can have severe consequences.","Wrong-route error assessment with poison control consultation.","advanced"),
  q("sq-bg6-43",ct,"new_nurse_anxiety","You feel you are not learning fast enough compared to expectations.","How would you address feeling behind in your orientation progress?","I would have an honest conversation with my preceptor: 'I feel I am progressing slower than expected in some areas. Can we review my competency checklist together and identify where I need more focused practice?' I would develop specific goals for each shift and track my improvement. I would not compare myself to other orientees—everyone learns at their own pace.","Honest self-assessment with targeted development plan.","beginner"),
  q("sq-bg6-44",pd,"patient_communication","A patient is angry about a long wait for test results.","How would you manage a patient's frustration about delays?","I would validate their frustration: 'I understand waiting is difficult, especially when you are anxious about results.' I would provide realistic expectations about timing. I would check on the status of results and communicate updates. I would not make promises I cannot keep. If there is a genuine delay, I would escalate to get information. Keeping patients informed reduces anxiety and frustration.","Proactive communication during wait times.","beginner"),
  q("sq-bg6-45",cn,"performance_evaluation","You receive contradictory feedback from different supervisors.","How would you navigate contradictory performance feedback?","I would seek clarification by meeting with both supervisors: 'I received feedback that seems to conflict. Can you help me understand the specific expectations so I can meet both?' I would document the conversation and develop a plan that addresses both perspectives. Sometimes contradictory feedback reflects different priority areas, and understanding context helps resolve the conflict.","Seeking clarification for conflicting feedback.","intermediate"),
  q("sq-bg6-46",ip,"clinical_judgment","A patient in sickle cell crisis develops sudden onset priapism.","How would you manage priapism in sickle cell disease?","Priapism is a urological emergency in sickle cell disease caused by vaso-occlusion in the penile vasculature. I would provide pain management, apply ice packs, encourage hydration, and notify the provider immediately for possible aspiration and irrigation. If untreated, priapism can cause permanent erectile dysfunction. This is a time-sensitive emergency that requires urological intervention.","Sickle cell priapism as a urological emergency.","advanced"),
  q("sq-bg6-47",ws,"difficult_coworkers","A colleague consistently arrives late to relieve you at shift change.","How would you address chronic late arrivals at shift change?","I would address it directly first: 'I have noticed you have been arriving late for the past several shifts. I understand things happen, but it affects my ability to leave on time and can impact patient safety during the transition. Is there something going on?' If the behavior continued after direct discussion, I would document each occurrence and escalate to the charge nurse and manager.","Direct communication followed by documentation.","beginner"),
  q("sq-bg6-48",ct,"documentation_challenges","You need to document a procedure you assisted with but did not perform.","How would you document assisting with a procedure?","I would document my role clearly: 'Assisted Dr. Smith with central line insertion. Prepared equipment, positioned patient, maintained sterile field, and monitored patient throughout. Patient tolerated procedure well. Post-procedure chest X-ray ordered for line placement verification.' I would not document the physician's actions in detail—they document their own procedure note.","Role-specific procedural documentation.","beginner"),
  q("sq-bg6-49",pd,"advocacy","A patient is being prescribed a medication they cannot afford.","How would you advocate for affordable medication alternatives?","I would discuss affordability concerns with the prescriber: 'The patient reports they cannot afford this medication. Are there generic alternatives, patient assistance programs, or therapeutic substitutions we can consider?' I would involve the pharmacist and social worker. I would help the patient apply for pharmaceutical company assistance programs. No patient should go without necessary medication due to cost.","Affordable medication advocacy.","beginner"),
  q("sq-bg6-50",cn,"career_advancement","You are interested in travel nursing.","How would you prepare for travel nursing?","I would gain at least 1-2 years of bedside experience in my specialty. I would develop strong clinical skills, adaptability, and independence. I would research travel nursing agencies, understand contract terms and compensation packages, and ensure my licensure is portable. I would develop comfort with rapid orientation to new environments. Travel nursing requires confidence, flexibility, and strong clinical competence.","Travel nursing preparation essentials.","beginner"),
  q("sq-bg6-51",ip,"clinical_judgment","A patient with cystic fibrosis has increasingly thick sputum despite chest physiotherapy.","How would you manage worsening CF symptoms?","I would increase frequency of chest physiotherapy and postural drainage, ensure adequate hydration, administer bronchodilators and mucolytics (dornase alfa) as ordered, obtain sputum culture for infection, and notify the provider about worsening symptoms. CF patients require aggressive airway clearance. I would also monitor nutrition as CF affects both respiratory and GI systems.","CF exacerbation management.","intermediate"),
  q("sq-bg6-52",ws,"patient_safety","A bariatric patient needs repositioning but only standard equipment is available.","How would you safely reposition a bariatric patient?","I would not attempt to reposition with inadequate equipment—this is an injury risk to both the patient and staff. I would request bariatric-specific equipment: appropriate bed, trapeze, and turning sheets. I would ensure adequate staff assistance (typically 3-4 people for large patients). I would follow safe patient handling guidelines and never compromise staff or patient safety due to equipment limitations.","Safe patient handling for bariatric patients.","intermediate"),
  q("sq-bg6-53",ct,"critical_thinking_drills","A patient's potassium is 2.8 mEq/L.","What are the dangers of moderate hypokalemia?","Potassium of 2.8 (normal 3.5-5.0) is moderate hypokalemia. Risks include cardiac arrhythmias (especially in patients on digoxin), muscle weakness, ileus, and respiratory compromise. I would place the patient on cardiac monitoring, check magnesium (hypomagnesemia prevents potassium correction), notify the provider, and anticipate oral or IV potassium replacement. I would monitor ECG for flattened T waves and U waves.","Hypokalemia management with magnesium awareness.","intermediate"),
  q("sq-bg6-54",pd,"ethical_dilemmas","You are caring for a patient who assaulted your colleague.","How would you provide unbiased care to a patient who hurt your colleague?","I would acknowledge my feelings privately—anger, resentment, and protectiveness toward my colleague are natural. However, I would provide the same standard of care. If I felt my bias would compromise care quality, I would request reassignment. I would ensure the patient is treated with professional respect while maintaining safety precautions. I would support my colleague through available resources.","Self-awareness and professional objectivity despite personal feelings.","advanced"),
  q("sq-bg6-55",ip,"scenario_responses","A patient asks why they have to wear the hospital gown and wants to wear their own clothes.","How would you handle a patient wanting personal clothing?","I would explain the clinical reasons: 'Hospital gowns provide easy access for assessments, monitoring leads, and emergency care. However, if your condition allows, I can check with your care team about wearing your own clothing during the day. Your comfort matters, and we can find a balance that works for both your comfort and clinical needs.'","Comfort accommodation within clinical requirements.","beginner"),
  q("sq-bg6-56",ws,"handoff_communication","The oncoming nurse has never cared for a patient with your patient's specific condition.","How would you enhance handoff for an unfamiliar condition?","I would provide additional education during handoff: key assessment parameters, expected versus concerning findings, medication-specific considerations, and common complications. I would provide reference materials and identify a resource nurse who has experience with the condition. I would offer my phone number for questions during the early hours of the next shift if appropriate.","Educational handoff enhancement for unfamiliar conditions.","intermediate"),
  q("sq-bg6-57",ct,"time_management","You are learning to manage four patients but previously only had two.","How would you scale up your patient assignment?","I would use a systematic brain sheet organizing all four patients' needs by time. I would identify which patients need the most attention and which are more stable. I would plan my first round to assess all patients quickly, then prioritize interventions. I would delegate appropriately and cluster care activities. Scaling up requires more structure, not just more speed.","Systematic scaling strategies for increased assignment.","beginner"),
  q("sq-bg6-58",pd,"advocacy","A patient needs a referral but the physician forgets to order it.","How would you follow up on unfulfilled clinical recommendations?","I would remind the physician politely: 'I noticed the cardiology referral we discussed yesterday has not been ordered yet. The patient is asking about it. Would you like me to initiate the order for your approval?' I would keep a list of pending referrals and follow up systematically. Nursing follow-through on referrals prevents patients from falling through the cracks.","Proactive referral follow-up advocacy.","beginner"),
  q("sq-bg6-59",cn,"probation_period","You are unsure whether to accept constructive criticism or push back.","How would you evaluate whether to accept or challenge feedback?","I would first listen fully without defending. I would ask myself: Is there truth in this feedback even if the delivery was poor? Does this align with feedback from others? Would implementing this change improve my practice? If the feedback is valid, I would accept it graciously and create an action plan. If I genuinely disagree, I would present my reasoning respectfully with specific examples.","Critical feedback evaluation framework.","beginner"),
  q("sq-bg6-60",ip,"clinical_judgment","A patient on a ventilator with ARDS requires prone positioning.","What are the considerations for prone positioning?","Prone positioning improves oxygenation in ARDS by redistributing lung perfusion and reducing compression of posterior lung segments. I would ensure adequate sedation, protect the face and pressure points, secure all lines and tubes, verify ETT position after turning, and monitor closely for complications including ETT displacement, facial edema, and pressure injuries. Prone positioning typically continues for 12-16 hours.","Prone positioning protocol and safety considerations.","advanced"),
  q("sq-bg6-61",ws,"interdisciplinary_communication","An occupational therapist reports concerns about patient safety that you did not observe.","How would you respond to another discipline's safety concern?","I would assess the patient myself to evaluate the OT's observations. Different disciplines see patients in different contexts—the patient may demonstrate deficits during OT sessions that are not apparent during nursing care. I would document both perspectives, communicate the concern to the medical team, and incorporate the OT's findings into the nursing care plan.","Integrating multi-disciplinary safety observations.","intermediate"),
  q("sq-bg6-62",ct,"first_shift","Your unit receives a surge of admissions and you feel overwhelmed.","How would you manage during a patient surge?","I would communicate with the charge nurse about the surge, accept direction on prioritization, focus on essential assessments and safety-critical tasks, delay non-urgent activities, and ask for help when needed. I would maintain situational awareness and not try to do everything at the same time. Surge situations require triage thinking—prioritize what will prevent the most harm.","Surge management with triage prioritization.","intermediate"),
  q("sq-bg6-63",pd,"patient_communication","A patient asks you personal questions about your health or lifestyle.","How would you redirect personal questions from patients?","I would redirect gently: 'I appreciate your curiosity, but I prefer to keep the focus on your care right now. Speaking of which, how are you feeling today?' I would not share personal health information as it can shift the therapeutic relationship. A brief, warm redirect maintains professionalism without being cold.","Gentle redirect of personal questions.","beginner"),
  q("sq-bg6-64",cn,"career_advancement","You are interested in becoming a nurse practitioner.","How would you plan your NP career pathway?","I would choose between FNP, ANP, PNP, PMHNP, or other specializations based on my clinical interests. I would gain 2+ years of clinical experience in a related specialty. I would research MSN and DNP programs, evaluate clinical hour requirements and placement support, and understand state practice authority. I would shadow NPs to understand the role before committing to a program.","NP career pathway planning.","intermediate"),
  q("sq-bg6-65",ip,"clinical_judgment","A patient who recently had a spinal cord injury develops autonomic dysreflexia.","What is the emergency response for autonomic dysreflexia?","Autonomic dysreflexia is a medical emergency in patients with spinal cord injuries at T6 or above. Symptoms include severe hypertension, pounding headache, diaphoresis above the injury level, and bradycardia. I would sit the patient upright immediately, remove tight clothing, check for the stimulating cause (most commonly a distended bladder or impacted bowel), catheterize if needed, and notify the provider. If unresolved, antihypertensive medication is needed urgently.","Autonomic dysreflexia emergency management.","advanced"),
  q("sq-bg6-66",ws,"medication_error","You accidentally waste a controlled substance without a witness.","How would you handle a witnessed waste requirement violation?","I would immediately inform the charge nurse about the witnessed waste violation. I would document the circumstances honestly and complete a medication error report. I would find a witness to co-sign the waste documentation as soon as possible, noting that the waste was performed before the witness was obtained. I would not falsify the witnessed waste documentation by having someone sign who did not actually witness it.","Honest reporting of controlled substance procedural violations.","intermediate"),
  q("sq-bg6-67",ct,"critical_thinking_drills","A patient has a mixed metabolic and respiratory acidosis.","What does combined acidosis indicate?","Mixed metabolic and respiratory acidosis (low pH, high CO2, low HCO3) is extremely dangerous and indicates both respiratory failure and metabolic derangement simultaneously. This is commonly seen in cardiac arrest, severe sepsis, or multisystem organ failure. The patient needs aggressive intervention: possible intubation for respiratory support, fluid resuscitation, and treatment of the underlying cause. This is often an ICU-level emergency.","Mixed acid-base disorder as a critical emergency.","advanced"),
  q("sq-bg6-68",pd,"workplace_bullying","A nurse manager retaliates after you file a safety concern.","How would you handle management retaliation?","I would document every retaliatory action with specific dates, witnesses, and details. I would report the retaliation to HR, the compliance hotline, and the next level of management. Retaliation for safety reporting is prohibited by law and most hospital policies. I would seek support from the nurses' union if applicable. I would not withdraw my safety report under pressure.","Legal protection awareness and documentation of retaliation.","advanced"),
  q("sq-bg6-69",cn,"performance_evaluation","Your evaluation includes feedback about communication skills.","How would you improve your communication skills based on feedback?","I would ask for specific examples of communication gaps. I would practice active listening, develop my SBAR framework, seek communication skills workshops, and ask for ongoing feedback. I would observe strong communicators on my unit and adopt their techniques. I would also improve my written communication through documentation reviews.","Targeted communication improvement with specific examples.","beginner"),
  q("sq-bg6-70",ip,"star_examples","Tell me about a time you adapted to a significant change.","How do you handle significant change?","When our unit transitioned from paper charting to electronic health records, many experienced nurses struggled. I embraced the change by completing extra training, creating tip sheets for common tasks, and serving as a resource for colleagues. While I was new, my comfort with technology allowed me to help experienced nurses adapt, strengthening our team relationships.","Change advocacy and peer support during transitions.","beginner"),
  q("sq-bg6-71",ws,"delegation","You delegate a task and the CNA does it incorrectly.","How would you address an incorrectly completed delegated task?","I would assess any patient impact first—did the error cause harm or change the patient's condition? I would then address the error constructively with the CNA: 'I noticed this was not completed as we discussed. Let me show you the correct approach so we can prevent this in the future.' I would re-do the task correctly if needed. I would reflect on whether my delegation instructions were clear enough.","Constructive error correction with self-reflection on delegation clarity.","beginner"),
  q("sq-bg6-72",ct,"documentation_challenges","You need to document a restraint application and ongoing monitoring.","What must be documented for patient restraints?","I would document: the specific behavior requiring restraints, less restrictive alternatives attempted and their results, type of restraint applied and time of application, provider order (must be obtained within a specified timeframe), patient assessment at required intervals (typically every 1-2 hours), neurovascular checks, release attempts, patient response, care provided during release, and ongoing reassessment of need.","Comprehensive restraint documentation requirements.","intermediate"),
  q("sq-bg6-73",pd,"professional_boundaries","A patient asks for a hug when they are feeling low.","How would you respond to a physical comfort request?","Brief, appropriate physical comfort like a hand on the shoulder or a side hug can be therapeutic and is often appropriate. I would assess the clinical context and my comfort level. I would not refuse in a way that feels rejecting. I would be mindful of the patient's cultural norms and personal space preferences. Professional touch is different from inappropriate physical contact.","Appropriate professional touch assessment.","beginner"),
  q("sq-bg6-74",ip,"clinical_judgment","A patient on MAO inhibitor antidepressants eats aged cheese and develops severe hypertension.","What is this food-drug interaction?","MAO inhibitors prevent tyramine metabolism. Foods high in tyramine (aged cheese, cured meats, red wine) can cause a hypertensive crisis when combined with MAOIs. With a blood pressure crisis, I would stop any MAOI-containing foods, administer antihypertensive medications as ordered (phentolamine may be used), monitor for signs of stroke or organ damage, and provide extensive dietary education to prevent recurrence.","MAOI-tyramine hypertensive crisis management.","advanced"),
  q("sq-bg6-75",cn,"career_advancement","You want to develop mentoring skills.","How would you become an effective mentor?","I would start by mentoring nursing students during their clinical rotations. I would learn effective mentoring techniques: active listening, constructive feedback delivery, Socratic questioning, and modeling professional behavior. I would attend preceptor development courses. I would reflect on what made my own mentors effective and incorporate those qualities. Mentoring is a skill that develops through practice and self-reflection.","Mentoring skill development through structured practice.","beginner"),
  q("sq-bg6-76",ip,"clinical_judgment","A patient develops severe itching, flushing, and bronchospasm during an MRI contrast injection.","What type of reaction is occurring?","This is an anaphylactic reaction to contrast media. I would stop the injection immediately, call for emergency assistance, maintain the airway, administer epinephrine IM, provide supplemental oxygen, establish IV access for fluid resuscitation, and be prepared for intubation. I would document the reaction and ensure the allergy is added to the patient's record. Future imaging should use alternative contrast or premedication protocols.","Contrast anaphylaxis emergency management.","advanced"),
  q("sq-bg6-77",ws,"patient_safety","A visitor brings alcohol into the patient's room.","How would you address alcohol brought into the hospital?","I would address it calmly: 'I understand wanting to make your visit special, but alcohol is not permitted in the hospital. It can interact with medications and affect treatment. I need to ask you to remove it from the room.' I would check on the patient to ensure they have not consumed any, and document the interaction. I would notify the charge nurse if needed.","Contraband management with patient safety explanation.","beginner"),
  q("sq-bg6-78",ct,"new_nurse_anxiety","You feel judged by experienced nurses when asking questions.","How would you overcome fear of asking questions?","I would remind myself that asking questions is a sign of professional responsibility, not weakness. I would choose my timing and audience wisely—asking during quiet moments and seeking out nurses who are patient and approachable. I would prepare my questions thoughtfully. I would remember that every experienced nurse was once new and asked the same questions. My patients' safety depends on my willingness to ask.","Reframing question-asking as professional strength.","beginner"),
  q("sq-bg6-79",pd,"advocacy","A non-English speaking patient signs consent forms they may not understand.","How would you ensure informed consent with language barriers?","I would stop the consent process and arrange for a certified medical interpreter. I would ensure the physician explains the procedure through the interpreter and the patient has the opportunity to ask questions. I would use teach-back through the interpreter to verify understanding. I would not allow a patient to sign consent forms they cannot read or understand—this violates informed consent principles.","Language-accessible informed consent protection.","intermediate"),
  q("sq-bg6-80",ip,"behavioral","Tell me about your understanding of evidence-based practice.","How do you incorporate evidence-based practice into your nursing care?","Evidence-based practice means integrating the best available research evidence with clinical expertise and patient preferences. I practiced this during clinical by researching current guidelines for wound care techniques before implementing them, questioning outdated practices I observed, and staying current with nursing literature. I believe EBP is not just an academic exercise—it directly improves patient outcomes.","Practical EBP understanding with clinical application.","beginner"),
  q("sq-bg6-81",ws,"handoff_communication","You discover a discrepancy in the medication reconciliation during your shift.","How would you address a medication reconciliation error?","I would stop, verify the correct medications with the patient and their pharmacy, correct the reconciliation in the chart, notify the provider about any medication discrepancies, and ensure the current medication orders reflect the accurate medication list. I would document the discovery and correction. Medication reconciliation errors are among the leading causes of preventable adverse drug events.","Medication reconciliation error correction process.","intermediate"),
  q("sq-bg6-82",ct,"critical_thinking_drills","A patient's carbon dioxide level on the metabolic panel is 15 mEq/L.","What does a low CO2 on the metabolic panel indicate?","CO2 on the metabolic panel represents bicarbonate (HCO3), not carbon dioxide gas. A level of 15 (normal 22-28) indicates metabolic acidosis. The body is either producing too much acid (DKA, lactic acidosis, toxins) or losing too much bicarbonate (diarrhea, renal tubular acidosis). I would check the anion gap to help determine the cause and correlate with clinical presentation.","Metabolic panel CO2 interpretation as bicarbonate.","intermediate"),
  q("sq-bg6-83",pd,"patient_communication","A patient with dementia becomes agitated during personal care.","How would you manage dementia-related agitation during care?","I would use a calm, gentle approach with simple instructions. I would maintain routine consistency, provide one-step directions, use distraction techniques, allow rest breaks, and reassess pain as a potential trigger. I would avoid rushing, arguing, or restraining. I would learn the patient's preferences and triggers from family members and incorporate them into the care plan.","Dementia-informed care approach during personal care.","intermediate"),
  q("sq-bg6-84",cn,"job_offer_negotiation","You are offered a position at a magnet hospital versus a non-magnet hospital.","How would you evaluate magnet status in job decisions?","Magnet designation indicates nursing excellence, strong leadership, and commitment to professional development. Benefits include better nurse-to-patient ratios, shared governance, and professional growth opportunities. However, non-magnet hospitals can also provide excellent environments. I would look beyond the label at specific factors: nurse satisfaction scores, turnover rates, orientation quality, and advancement opportunities.","Evidence-based evaluation beyond designation labels.","intermediate"),
  q("sq-bg6-85",ip,"clinical_judgment","A patient develops fat embolism syndrome after a long bone fracture.","How would you recognize fat embolism syndrome?","Fat embolism syndrome typically occurs 12-72 hours after long bone fractures. Classic triad: respiratory distress, neurological changes, and petechial rash (especially on the chest, axillae, and conjunctivae). I would provide respiratory support with high-flow oxygen, monitor neurological status, keep the patient immobilized, and notify the provider. Treatment is primarily supportive. Early fracture fixation reduces risk.","Fat embolism syndrome recognition after fractures.","advanced"),
  q("sq-bg6-86",ws,"difficult_coworkers","A colleague vents excessively about personal problems during work.","How would you manage a colleague who overshares personal issues?","I would be compassionate but set boundaries: 'I care about what you are going through. However, I need to focus on patient care right now. Can we talk during lunch or after the shift?' I would recommend EAP services if their issues seem significant. I would not let excessive venting distract from patient care or become a substitute for professional support.","Compassionate boundary-setting with resource referral.","beginner"),
  q("sq-bg6-87",ct,"time_management","You are constantly interrupted by phone calls from physicians, labs, and families.","How would you manage constant interruptions?","I would implement strategies: batch non-urgent calls for specific times, use a communication device that allows prioritization, set expectations with families about callback times, and protect critical task periods. I would communicate with the unit clerk about screening non-urgent calls. For safety-critical tasks like medication administration, I would use a 'do not disturb' indication.","Systematic interruption management.","intermediate"),
  q("sq-bg6-88",pd,"ethical_dilemmas","A patient asks you not to tell their spouse about their HIV diagnosis.","How would you handle a patient's request for confidentiality about a communicable disease?","I would respect the patient's confidentiality while educating them about partner notification: 'Your diagnosis is confidential. However, your partner's health is also at risk. Many health departments offer anonymous partner notification services so your partner can be informed and tested without your name being disclosed. Can I connect you with those services?' I would follow state reporting requirements.","Confidentiality balance with partner notification education.","advanced"),
  q("sq-bg6-89",cn,"career_advancement","You want to develop your critical care skills for ICU nursing.","How would you prepare for ICU nursing?","I would pursue ACLS and PALS certification, seek high-acuity experiences on my current unit, complete critical care courses or a critical care fellowship program, study hemodynamic monitoring and ventilator management, and shadow ICU nurses. I would develop comfort with invasive lines, drips, and rapid clinical decision-making. ICU nursing requires both strong clinical skills and emotional resilience.","ICU preparation through progressive skill development.","intermediate"),
  q("sq-bg6-90",ip,"scenario_responses","A patient is texting during your discharge education.","How would you address distraction during patient education?","I would pause and address it gently: 'I want to make sure you understand everything before you go home. The information I am sharing could prevent you from needing to come back. Can I have your full attention for the next 10 minutes? Then you can get back to your messages.' I would also provide written materials as a backup and have them sign acknowledging receipt of education materials.","Respectful attention management during education.","beginner"),
  q("sq-bg6-91",ws,"patient_safety","A patient with a known seizure disorder is prescribed a medication that lowers seizure threshold.","How would you address a medication that could trigger seizures?","I would verify the order with the prescriber: 'I want to confirm this medication for a patient with a seizure history, as it is known to lower the seizure threshold. Has the risk been weighed against the benefit?' I would implement seizure precautions regardless and document my communication. Not all seizure-threshold-lowering medications are contraindicated, but the prescriber should make an informed decision.","Pharmacological seizure risk awareness.","intermediate"),
  q("sq-bg6-92",ct,"critical_thinking_drills","A post-operative patient develops a wound dehiscence with evisceration.","What is the immediate response to wound evisceration?","Evisceration (protrusion of internal organs through a surgical wound) is a surgical emergency. I would call for immediate help, keep the patient calm and supine with knees bent, cover the exposed organs with sterile saline-soaked gauze (never attempt to push organs back in), and notify the surgeon for emergent return to the operating room. I would assess vital signs and prepare for surgery.","Evisceration emergency response protocol.","advanced"),
  q("sq-bg6-93",pd,"patient_communication","A patient asks about complementary therapies for their chronic pain.","How would you discuss complementary pain management?","I would be open and informed: 'Many patients find complementary approaches helpful for chronic pain. Options with evidence support include acupuncture, massage, meditation, yoga, and cognitive behavioral therapy. These work best alongside your prescribed treatment plan, not as replacements. Would you like me to arrange a referral to our integrative medicine program?' I would document the discussion and referral.","Evidence-informed complementary therapy discussion.","beginner"),
  q("sq-bg6-94",cn,"probation_period","You want to develop your critical care response skills during orientation.","How would you build emergency response skills during orientation?","I would participate in all simulation exercises, attend code team practice sessions, review emergency protocols regularly, volunteer to assist during codes on the unit, and debrief with my preceptor after every emergency event. I would practice ACLS scenarios mentally and physically. I would ask my preceptor to include me in rapid response team activations so I can gain experience in a supported environment.","Progressive emergency skill building during orientation.","beginner"),
  q("sq-bg6-95",ip,"clinical_judgment","A patient with liver cirrhosis develops ascites and their weight increases by 10 pounds in 3 days.","How would you manage rapid fluid accumulation in cirrhosis?","Rapid weight gain with ascites indicates fluid retention from portal hypertension and hypoalbuminemia. I would assess for respiratory compromise from the ascites, restrict sodium and fluids per orders, administer diuretics (typically spironolactone and furosemide), measure abdominal girth daily, and monitor electrolytes. If ascites is tense and causing respiratory distress, I would anticipate therapeutic paracentesis.","Ascites management with monitoring parameters.","intermediate"),
  q("sq-bg6-96",ws,"delegation","A student nurse asks to start an IV on your patient.","How would you supervise a student nurse's IV attempt?","I would verify with their clinical instructor that the student is authorized for IV insertion. I would ensure the patient consents to student involvement. I would prepare all supplies, coach the student through the procedure, and be ready to take over if needed. I would limit attempts (typically 2) to protect the patient. I would provide constructive feedback after the attempt.","Supervised student skill practice with patient protection.","beginner"),
  q("sq-bg6-97",ct,"documentation_challenges","You need to document a telephone order from a physician.","How would you properly document a telephone order?","I would write or enter the order using the read-back verification method: I would read the complete order back to the physician and have them confirm its accuracy. I would document 'Telephone order from Dr. [name], read back and verified' with the date and time. I would sign the order and ensure the physician co-signs within the required timeframe per facility policy.","Telephone order documentation with read-back verification.","beginner"),
  q("sq-bg6-98",pd,"advocacy","A patient wants to donate organs but their family objects.","How would you navigate organ donation discussions?","I would support the patient's documented wishes regarding organ donation. I would involve the organ procurement organization for professional counseling. I would help facilitate a family discussion about the patient's values and wishes. I would ensure the patient's registered organ donor status is documented. While family support is important, the patient's autonomous decision should be respected.","Patient autonomy advocacy in organ donation.","advanced"),
  q("sq-bg6-99",cn,"career_advancement","You want to explore international nursing opportunities.","How would you pursue international nursing?","I would research organizations that place nurses internationally (WHO, MSF, Peace Corps). I would ensure my credentials are transferable, develop cross-cultural competency, learn a second language, pursue tropical medicine or global health coursework, and gain diverse clinical experience. International nursing requires adaptability, independence, and comfort with resource-limited settings.","International nursing preparation.","intermediate"),
  q("sq-bg6-100",ip,"clinical_judgment","A patient on continuous renal replacement therapy develops citrate toxicity.","How would you recognize citrate toxicity during CRRT?","Citrate is used as an anticoagulant in CRRT and is normally metabolized by the liver. In liver failure patients, citrate can accumulate causing hypocalcemia, metabolic alkalosis, and widened total-to-ionized calcium ratio. I would monitor ionized calcium closely, assess for symptoms (tingling, hypotension, cardiac arrhythmias), and notify the provider for citrate dose adjustment or switch to alternative anticoagulation.","CRRT citrate toxicity recognition.","advanced"),
];
